import { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { Pin, Plus, Trash2, Search, Loader2 } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { useNearbyFoodPinsAdmin } from "@/hooks/useNearbyFoodPins";
import { supabase } from "@/integrations/supabase/client";
import { useQuery } from "@tanstack/react-query";

type SearchRow = { id: string; name: string; city: string | null; image_url: string | null };

const AdminNearbyFoodPins = () => {
  const { t } = useTranslation();
  const { list, add, update, remove } = useNearbyFoodPinsAdmin();

  const [open, setOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [selected, setSelected] = useState<SearchRow | null>(null);
  const [sortOrder, setSortOrder] = useState<number>(0);
  const [note, setNote] = useState("");

  const search = useQuery({
    queryKey: ["pin-restaurant-search", searchTerm],
    enabled: open && searchTerm.trim().length >= 2,
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("id,name,city,image_url")
        .eq("visible", true)
        .eq("archived", false)
        .or(`name.ilike.%${searchTerm}%,name_en.ilike.%${searchTerm}%,name_pt.ilike.%${searchTerm}%`)
        .limit(20);
      if (error) throw error;
      return (data || []) as SearchRow[];
    },
  });

  const reset = () => {
    setSearchTerm("");
    setSelected(null);
    setSortOrder(0);
    setNote("");
  };

  const handleSubmit = async () => {
    if (!selected) return;
    await add.mutateAsync({ restaurant_id: selected.id, sort_order: sortOrder, note: note || null });
    if (!add.isError) {
      setOpen(false);
      reset();
    }
  };

  const rows = list.data || [];

  return (
    <div className="container mx-auto p-4 md:p-6 space-y-6">
      <Card>
        <CardHeader>
          <div className="flex items-start justify-between gap-4 flex-wrap">
            <div className="space-y-1">
              <CardTitle className="flex items-center gap-2">
                <Pin className="w-5 h-5" />
                {t("admin.nearbyFoodPins.title")}
              </CardTitle>
              <CardDescription>{t("admin.nearbyFoodPins.description")}</CardDescription>
            </div>
            <Button onClick={() => setOpen(true)} className="gap-1.5">
              <Plus className="w-4 h-4" />
              {t("admin.nearbyFoodPins.addPin")}
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {list.isLoading ? (
            <div className="flex items-center justify-center py-10 text-muted-foreground">
              <Loader2 className="w-5 h-5 animate-spin mr-2" />
            </div>
          ) : rows.length === 0 ? (
            <p className="text-center text-muted-foreground py-10">{t("admin.nearbyFoodPins.empty")}</p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>{t("admin.nearbyFoodPins.restaurant")}</TableHead>
                  <TableHead>{t("admin.nearbyFoodPins.city")}</TableHead>
                  <TableHead className="w-28">{t("admin.nearbyFoodPins.sortOrder")}</TableHead>
                  <TableHead>{t("admin.nearbyFoodPins.note")}</TableHead>
                  <TableHead className="w-28 text-right">{t("admin.nearbyFoodPins.actions")}</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {rows.map((row) => (
                  <TableRow key={row.id}>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        {row.restaurants?.image_url && (
                          <img src={row.restaurants.image_url} alt="" className="w-8 h-8 rounded object-cover" />
                        )}
                        <span className="font-medium">{row.restaurants?.name || row.restaurant_id}</span>
                      </div>
                    </TableCell>
                    <TableCell className="text-muted-foreground">{row.restaurants?.city || "-"}</TableCell>
                    <TableCell>
                      <Input
                        type="number"
                        defaultValue={row.sort_order}
                        className="h-8 w-20"
                        onBlur={(e) => {
                          const v = Number(e.target.value);
                          if (v !== row.sort_order) update.mutate({ id: row.id, sort_order: v });
                        }}
                      />
                    </TableCell>
                    <TableCell>
                      <Input
                        defaultValue={row.note || ""}
                        className="h-8"
                        onBlur={(e) => {
                          if (e.target.value !== (row.note || "")) update.mutate({ id: row.id, note: e.target.value });
                        }}
                      />
                    </TableCell>
                    <TableCell className="text-right">
                      <AlertDialog>
                        <AlertDialogTrigger asChild>
                          <Button size="sm" variant="ghost" className="text-destructive">
                            <Trash2 className="w-4 h-4" />
                          </Button>
                        </AlertDialogTrigger>
                        <AlertDialogContent>
                          <AlertDialogHeader>
                            <AlertDialogTitle>{t("admin.nearbyFoodPins.deleteConfirm")}</AlertDialogTitle>
                            <AlertDialogDescription>{row.restaurants?.name}</AlertDialogDescription>
                          </AlertDialogHeader>
                          <AlertDialogFooter>
                            <AlertDialogCancel>{t("admin.nearbyFoodPins.cancel")}</AlertDialogCancel>
                            <AlertDialogAction onClick={() => remove.mutate(row.id)}>
                              {t("admin.nearbyFoodPins.delete")}
                            </AlertDialogAction>
                          </AlertDialogFooter>
                        </AlertDialogContent>
                      </AlertDialog>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) reset(); }}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.nearbyFoodPins.addPin")}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label>{t("admin.nearbyFoodPins.searchRestaurant")}</Label>
              <div className="relative">
                <Search className="absolute left-2.5 top-2.5 w-4 h-4 text-muted-foreground" />
                <Input
                  className="pl-8"
                  placeholder={t("admin.nearbyFoodPins.searchRestaurant")}
                  value={searchTerm}
                  onChange={(e) => { setSearchTerm(e.target.value); setSelected(null); }}
                />
              </div>
              {searchTerm.length >= 2 && (
                <div className="max-h-60 overflow-y-auto border rounded-md divide-y">
                  {search.isLoading && (
                    <div className="p-3 text-sm text-muted-foreground flex items-center gap-2">
                      <Loader2 className="w-4 h-4 animate-spin" />
                    </div>
                  )}
                  {(search.data || []).map((r) => (
                    <button
                      key={r.id}
                      type="button"
                      onClick={() => setSelected(r)}
                      className={`w-full flex items-center gap-2 p-2 text-left hover:bg-accent transition-colors ${selected?.id === r.id ? "bg-accent" : ""}`}
                    >
                      {r.image_url && <img src={r.image_url} alt="" className="w-8 h-8 rounded object-cover" />}
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">{r.name}</p>
                        <p className="text-xs text-muted-foreground truncate">{r.city || ""}</p>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div className="space-y-2">
              <Label>{t("admin.nearbyFoodPins.sortOrder")}</Label>
              <Input type="number" value={sortOrder} onChange={(e) => setSortOrder(Number(e.target.value))} />
            </div>

            <div className="space-y-2">
              <Label>{t("admin.nearbyFoodPins.note")}</Label>
              <Textarea value={note} onChange={(e) => setNote(e.target.value)} rows={2} />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setOpen(false)}>{t("admin.nearbyFoodPins.cancel")}</Button>
            <Button onClick={handleSubmit} disabled={!selected || add.isPending}>
              {add.isPending && <Loader2 className="w-4 h-4 animate-spin mr-1.5" />}
              {t("admin.nearbyFoodPins.save")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default AdminNearbyFoodPins;
